
.setup-shell {
  width: 100%;
  max-width: 760px;
  margin: 0 auto 13px;
}

.saved-ticket {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr) auto;
  align-items: center;
  gap: 11px;
  padding: 10px 12px;
  border: 1px solid var(--line-strong);
  background:
    repeating-linear-gradient(90deg, transparent 0 18px, rgba(98, 80, 113, 0.035) 18px 19px), var(--surface-paper);
  box-shadow: 3px 3px 0 var(--shadow-frame);
  animation: foldTicket 260ms ease-out both;
}

.ticket-status {
  display: grid;
  width: 32px;
  height: 32px;
  place-items: center;
  border: 1px solid var(--accent-signal);
  background: var(--accent-signal-soft);
  color: var(--accent-signal);
  font-family: var(--font-data);
  font-weight: 700;
}

.ticket-copy {
  min-width: 0;
}

.ticket-label {
  margin: 0;
  color: var(--ink-muted);
  font-family: var(--font-data);
  font-size: 0.59rem;
  letter-spacing: 0.07em;
}

.ticket-copy strong {
  color: var(--accent-primary-strong);
  font-size: 0.84rem;
}

.ticket-copy p:last-child {
  overflow: hidden;
  margin: 2px 0 0;
  color: var(--ink-secondary);
  font-size: 0.7rem;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.saved-ticket button {
  min-width: 48px;
  min-height: 38px;
  border: 1px solid var(--line-soft);
  background: var(--surface-muted);
  color: var(--accent-primary-strong);
  cursor: pointer;
  font: inherit;
  font-size: 0.75rem;
  font-weight: 700;
}

.saved-ticket button:focus-visible {
  outline: 2px solid var(--accent-signal);
  outline-offset: 2px;
}

.save-notice {
  margin: 6px 0 0;
  padding: 5px 8px;
  border-left: 3px solid var(--accent-signal);
  background: var(--accent-signal-soft);
  color: var(--ink-secondary);
  font-size: 0.7rem;
}

@keyframes foldTicket {
  from {
    opacity: 0.52;
    transform: scaleY(0.94);
    transform-origin: top;
  }
  to {
    opacity: 1;
    transform: scaleY(1);
    transform-origin: top;
  }
}

@media (max-width: 520px) {
  .saved-ticket {
    grid-template-columns: auto minmax(0, 1fr);
    box-shadow: 1px 1px 0 var(--shadow-frame);
  }

  .saved-ticket button {
    grid-column: 2;
    justify-self: end;
  }
}

@media (prefers-reduced-motion: reduce) {
  .saved-ticket {
    animation: none;
  }
}
